import React, { useEffect, useRef, useState } from 'react';
import { Box, AppBar, Toolbar, Typography, IconButton, Drawer, List, ListItem, ListItemIcon, ListItemText, Slider, Divider } from '@mui/material';
import { fabric } from 'fabric';
import styled from 'styled-components';
import {
  Brush as BrushIcon,
  Undo as UndoIcon,
  Redo as RedoIcon,
  Delete as DeleteIcon,
  ColorLens as ColorLensIcon,
  RadioButtonUnchecked as CircleIcon,
  CropSquare as RectangleIcon,
} from '@mui/icons-material';

const CanvasContainer = styled(Box)`
  flex-grow: 1;
  height: calc(100vh - 64px);
  background: white;
  position: relative;
  display: flex;
  justify-content: center;
  align-items: center;
`;

const ToolbarButton = styled(IconButton)`
  margin: 0 8px;
  color: white;
`;

const ColorPicker = styled.input`
  width: 50px;
  height: 50px;
  padding: 0;
  border: none;
  border-radius: 4px;
  cursor: pointer;
`;

const StyledCanvas = styled.canvas`
  border: 1px solid #ccc;
  margin: 20px;
`;

function App() {
  const canvasRef = useRef(null);
  const [canvas, setCanvas] = useState(null);
  const [drawerOpen, setDrawerOpen] = useState(false);
  const [currentColor, setCurrentColor] = useState('#000000');
  const [currentWidth, setCurrentWidth] = useState(2);

  useEffect(() => {
    if (canvasRef.current) {
      const canvas = new fabric.Canvas(canvasRef.current, {
        width: 800,
        height: 600,
        backgroundColor: '#ffffff',
      });

      // Add grid
      const gridSize = 20;
      for (let i = 0; i < canvas.width; i += gridSize) {
        canvas.add(new fabric.Line([i, 0, i, canvas.height], {
          stroke: '#e0e0e0',
          selectable: false,
        }));
      }
      for (let i = 0; i < canvas.height; i += gridSize) {
        canvas.add(new fabric.Line([0, i, canvas.width, i], {
          stroke: '#e0e0e0',
          selectable: false,
        }));
      }

      // Add axes
      const xAxis = new fabric.Line([0, canvas.height/2, canvas.width, canvas.height/2], {
        stroke: '#000000',
        selectable: false,
      });
      const yAxis = new fabric.Line([canvas.width/2, 0, canvas.width/2, canvas.height], {
        stroke: '#000000',
        selectable: false,
      });
      canvas.add(xAxis, yAxis);

      setCanvas(canvas);

      return () => {
        canvas.dispose();
      };
    }
  }, []);

  const handleUndo = () => {
    if (canvas) {
      const objects = canvas.getObjects();
      if (objects.length > 0) {
        canvas.remove(objects[objects.length - 1]);
        canvas.renderAll();
      }
    }
  };

  const handleDelete = () => {
    if (canvas) {
      const activeObject = canvas.getActiveObject();
      if (activeObject) {
        canvas.remove(activeObject);
        canvas.renderAll();
      }
    }
  };

  const handleDrawRectangle = () => {
    if (canvas) {
      const rect = new fabric.Rect({
        left: 100,
        top: 100,
        width: 100,
        height: 100,
        fill: 'transparent',
        stroke: currentColor,
        strokeWidth: currentWidth,
      });
      canvas.add(rect);
      canvas.renderAll();
    }
  };

  const handleDrawCircle = () => {
    if (canvas) {
      const circle = new fabric.Circle({
        left: 100,
        top: 100,
        radius: 50,
        fill: 'transparent',
        stroke: currentColor,
        strokeWidth: currentWidth,
      });
      canvas.add(circle);
      canvas.renderAll();
    }
  };

  return (
    <Box sx={{ display: 'flex', flexDirection: 'column', height: '100vh', bgcolor: 'background.default' }}>
      <AppBar position="static" sx={{ bgcolor: 'primary.main' }}>
        <Toolbar>
          <Typography variant="h6" component="div" sx={{ flexGrow: 1, color: 'white' }}>
            Draze - Where Shapes Take Form
          </Typography>
          <ToolbarButton onClick={() => setDrawerOpen(true)}>
            <BrushIcon />
          </ToolbarButton>
          <ToolbarButton onClick={handleUndo}>
            <UndoIcon />
          </ToolbarButton>
          <ToolbarButton onClick={handleDelete}>
            <DeleteIcon />
          </ToolbarButton>
        </Toolbar>
      </AppBar>

      <Drawer
        anchor="left"
        open={drawerOpen}
        onClose={() => setDrawerOpen(false)}
        sx={{
          '& .MuiDrawer-paper': {
            width: 240,
            boxSizing: 'border-box',
            bgcolor: 'background.paper',
          },
        }}
      >
        <List>
          <ListItem button onClick={handleDrawRectangle}>
            <ListItemIcon>
              <RectangleIcon />
            </ListItemIcon>
            <ListItemText primary="Rectangle" />
          </ListItem>
          <ListItem button onClick={handleDrawCircle}>
            <ListItemIcon>
              <CircleIcon />
            </ListItemIcon>
            <ListItemText primary="Circle" />
          </ListItem>
          <Divider sx={{ my: 2 }} />
          <ListItem>
            <ListItemIcon>
              <ColorLensIcon />
            </ListItemIcon>
            <ColorPicker
              type="color"
              value={currentColor}
              onChange={(e) => setCurrentColor(e.target.value)}
            />
          </ListItem>
          <ListItem>
            <ListItemText primary="Line Width" />
            <Slider
              value={currentWidth}
              onChange={(e, newValue) => setCurrentWidth(newValue)}
              min={1}
              max={10}
              sx={{ width: 100 }}
            />
          </ListItem>
        </List>
      </Drawer>

      <CanvasContainer>
        <StyledCanvas ref={canvasRef} />
      </CanvasContainer>
    </Box>
  );
}

export default App;
